def fix_descriptions():
    """Replace generic SEO descriptions with unique, keyword-rich ones."""
    # Load calculators.json to get input/output data for descriptions we don't have
    with open(os.path.join(CALC_DIR, 'calculators.json'), 'r', encoding='utf-8') as f:
        calcs = json.load(f)['calculators']
    
    calc_by_id = {str(c['id']): c for c in calcs}
    
    for lang in LANGS:
        fpath = os.path.join(I18N_DIR, f'{lang}.json')
        with open(fpath, 'r', encoding='utf-8') as f:
            data = json.load(f)
        
        calcs_i18n = data['calculators']
        changed = 0
        
        for calc_id, entry in calcs_i18n.items():
            desc = entry.get('seo_description', entry.get('seo_desc', ''))
            
            # Check if description is generic
            is_generic = False
            generic_markers = [
                'Calculate instantly with step-by-step results',
                'Calculate instantly and for free',
                'Calcula al instante con resultados paso a paso',
                'Calculez instantan',
                'Calcule instantaneamente com resultados passo a passo',
                'Sofort berechnen mit schrittweisen Ergebnissen',
                'Calcola istantaneamente con risultati dettagliati',
            ]
            for marker in generic_markers:
                if marker in desc:
                    is_generic = True
                    break
            if not is_generic and (desc == entry.get('name', '') + '.' or desc == entry.get('name', '')):
                is_generic = True
            
            if not is_generic:
                continue
            
            # Use our custom descriptions if available
            if calc_id in DESC_TEMPLATES and lang in DESC_TEMPLATES[calc_id]:
                entry['seo_description'] = DESC_TEMPLATES[calc_id][lang]
                entry['seo_desc'] = entry['seo_description']
                changed += 1
            else:
                # Generate from name
                name = entry.get('name', '')
                if lang == 'en':
                    entry['seo_description'] = f"{name}. Calculate instantly with step-by-step results. Free online tool by CalcToWork."
                elif lang == 'es':
                    entry['seo_description'] = f"{name}. Calcula al instante con resultados paso a paso. Herramienta gratuita de CalcToWork."
                elif lang == 'fr':
                    entry['seo_description'] = f"{name}. Calculez instantanement avec des resultats detailles. Outil gratuit par CalcToWork."
                elif lang == 'pt':
                    entry['seo_description'] = f"{name}. Calcule instantaneamente com resultados passo a passo. Ferramenta gratuita da CalcToWork."
                elif lang == 'de':
                    entry['seo_description'] = f"{name}. Sofort berechnen mit schrittweisen Ergebnissen. Kostenloses Online-Tool von CalcToWork."
                elif lang == 'it':
                    entry['seo_description'] = f"{name}. Calcola istantaneamente con risultati dettagliati. Strumento gratuito di CalcToWork."
                entry['seo_desc'] = entry['seo_description']
                changed += 1
        
        with open(fpath, 'w', encoding='utf-8') as f:
            json.dump(data, f, ensure_ascii=False, indent=2)
            f.write('\n')
        
        print(f'  Fixed {changed} descriptions in {lang}.json')


if __name__ == '__main__':
    print('Fixing generic SEO descriptions...')
    fix_descriptions()
    print('Done!')